<script setup lang="ts">
import axios from 'axios';
import { initBots } from '@/stores/ftbotwrapper';
import LumiTraderChat from '@/views/LumiChatView.vue';

const settingsStore = useSettingsStore();
const colorStore = useColorStore();

/* ── App-level auth gate ── */
// 3 states: 'splash' → 'login' → 'app'
const appState = ref<'splash' | 'login' | 'app'>('splash');
const googleEnabled = ref(false);

// PB user info — shared with NavBar via provide/inject
const pbUser = ref<{ id: string; email: string; name: string; avatarUrl?: string } | null>(null);
provide('pbUser', pbUser);

// Logout — clears PB session + freqtrade tokens + reloads
async function doLogout() {
  try { await fetch('/lc/auth/logout', { method: 'POST', credentials: 'include' }); } catch {}
  localStorage.removeItem('ftAuthLoginInfo');
  localStorage.removeItem('ftSelectedBot');
  pbUser.value = null;
  appState.value = 'login';
  loginStep.value = 'welcome';
  loginError.value = '';
}
provide('doLogout', doLogout);
const loginStep = ref<'welcome' | 'password' | 'register'>('welcome');
const loginEmail = ref('');
const loginPassword = ref('');
const loginName = ref('');
const loginPassword2 = ref('');
const loginError = ref('');
const loginLoading = ref(false);

async function checkAuthAndInit() {
  const startTime = Date.now();

  // Check Google OAuth
  try {
    const r = await fetch('/lc/auth/methods', { credentials: 'same-origin' });
    if (r.ok) { const d = await r.json(); if (d.google) googleEnabled.value = true; }
  } catch {}

  // Check PB session + get user info
  let loggedIn = false;
  try {
    const r = await fetch('/lc/auth/me', { credentials: 'include' });
    if (r.ok) {
      const data = await r.json();
      pbUser.value = {
        id: data.id || data.record?.id || '',
        email: data.email || data.record?.email || '',
        name: data.name || data.record?.name || '',
        avatarUrl: data.avatarUrl || data.record?.avatarUrl || '',
      };
      loggedIn = true;
    }
  } catch {}

  // Wait for splash to finish (minimum 2s total)
  const elapsed = Date.now() - startTime;
  if (elapsed < 2000) {
    await new Promise(resolve => setTimeout(resolve, 2000 - elapsed));
  }

  if (loggedIn) {
    await doFreqtradeAutoLogin();
  } else {
    appState.value = 'login';
  }
}

function googleLogin() {
  window.location.href = '/lc/auth/oauth-start?provider=google&redirect=' + encodeURIComponent('/lumitrade/');
}

async function continueWithEmail() {
  loginError.value = '';
  if (!loginEmail.value.trim()) { loginError.value = 'Please enter your email'; return; }
  loginLoading.value = true;
  try {
    const r = await fetch('/lc/auth/check-email', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email: loginEmail.value.trim() }),
    });
    const d = await r.json();
    loginStep.value = d.exists ? 'password' : 'register';
  } catch { loginStep.value = 'password'; }
  loginLoading.value = false;
}

async function doLogin() {
  loginError.value = '';
  if (!loginPassword.value) { loginError.value = 'Password required'; return; }
  loginLoading.value = true;
  try {
    const r = await fetch('/lc/auth/login', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ email: loginEmail.value.trim(), password: loginPassword.value }),
    });
    if (!r.ok) {
      const d = await r.json().catch(() => ({}));
      loginError.value = d.error || d.message || 'Login failed';
      loginLoading.value = false; return;
    }
    // Fetch user info after login
    try {
      const me = await fetch('/lc/auth/me', { credentials: 'include' });
      if (me.ok) { const d = await me.json(); pbUser.value = { id: d.id||d.record?.id||'', email: d.email||d.record?.email||'', name: d.name||d.record?.name||'', avatarUrl: d.avatarUrl||'' }; }
    } catch {}
    await doFreqtradeAutoLogin();
  } catch (e: any) { loginError.value = e.message || 'Login failed'; loginLoading.value = false; }
}

async function doRegister() {
  loginError.value = '';
  if (!loginName.value.trim()) { loginError.value = 'Name required'; return; }
  if (loginPassword.value.length < 8) { loginError.value = 'Password must be at least 8 characters'; return; }
  if (loginPassword.value !== loginPassword2.value) { loginError.value = 'Passwords do not match'; return; }
  loginLoading.value = true;
  try {
    const r = await fetch('/lc/auth/register', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ email: loginEmail.value.trim(), password: loginPassword.value, name: loginName.value.trim() }),
    });
    if (!r.ok) {
      const d = await r.json().catch(() => ({}));
      loginError.value = d.error || d.message || 'Registration failed';
      loginLoading.value = false; return;
    }
    await doFreqtradeAutoLogin();
  } catch (e: any) { loginError.value = e.message || 'Registration failed'; loginLoading.value = false; }
}

async function doFreqtradeAutoLogin() {
  try {
    const { data: creds } = await axios.get('/lumitrade/auto-auth', { timeout: 3000 });
    if (!creds?.username) throw new Error('no creds');
    const apiUrl = window.location.origin + '/lumitrade';
    const { data: tokenResp } = await axios.post(
      '/lumitrade/api/v1/token/login', {},
      { auth: { username: creds.username, password: creds.password }, timeout: 5000 },
    );
    if (!tokenResp?.access_token) throw new Error('no token');

    const BOT_ID = 'ftbot.0';
    const authStorage: Record<string, any> = {
      [BOT_ID]: {
        botName: creds.botName || 'LumiTrade', apiUrl,
        username: creds.username, refreshToken: tokenResp.refresh_token,
        accessToken: tokenResp.access_token, autoRefresh: true, sortId: 0,
      },
    };
    try {
      const { data: bt } = await axios.post(
        '/lumitrade/bt/api/v1/token/login', {},
        { auth: { username: creds.username, password: creds.password }, timeout: 5000 },
      );
      if (bt?.access_token) {
        authStorage['ftbot.1'] = {
          botName: 'Backtest', apiUrl: window.location.origin + '/lumitrade/bt',
          username: creds.username, refreshToken: bt.refresh_token,
          accessToken: bt.access_token, autoRefresh: true, sortId: 1,
        };
      }
    } catch {}
    localStorage.setItem('ftAuthLoginInfo', JSON.stringify(authStorage));
    localStorage.setItem('ftSelectedBot', BOT_ID);
    // Initialize FreqUI bot stores from the credentials we just stored.
    // Must be called BEFORE setting appState='app' so NavBar/BodyLayout
    // see a populated botStore on first render.
    initBots();
    appState.value = 'app';
  } catch {
    loginError.value = 'Failed to connect to trading engine';
    appState.value = 'login';
    loginLoading.value = false;
  }
}

// Splash minimum time (2s for ball animation)
const splashMinDone = ref(false);
setTimeout(() => { splashMinDone.value = true; }, 2000);

// checkAuthAndInit() is called inside onMounted below

/* ── LumiTrader floating panel state ── */
const lumiChatOpen = ref(false);
const panelPos = ref({ x: -1, y: -1 });
const isDragging = ref(false);
const dragOffset = ref({ x: 0, y: 0 });
const panelClosing = ref(false);

const route = useRoute();
const router = useRouter();

function toggleLumiChat() {
  lumiChatOpen.value = !lumiChatOpen.value;
}

function closePanelWithAnimation() {
  if (!lumiChatOpen.value) return;
  panelClosing.value = true;
  setTimeout(() => {
    lumiChatOpen.value = false;
    panelClosing.value = false;
  }, 280);
}

watch(() => route.path, (newPath) => {
  if (newPath === '/chat' && lumiChatOpen.value) closePanelWithAnimation();
});

// Session keepalive — refresh PB token every 30min if user active
let lastActivity = Date.now();
const ACTIVITY_EVENTS = ['mousemove', 'keydown', 'click', 'touchstart', 'scroll'];

function trackActivity() { lastActivity = Date.now(); }

// Start keepalive when app state becomes 'app'
watch(appState, (state) => {
  if (state === 'app') {
    ACTIVITY_EVENTS.forEach(e => window.addEventListener(e, trackActivity, { passive: true }));

    setInterval(async () => {
      // Only refresh if user was active in last 10 minutes
      if (Date.now() - lastActivity > 10 * 60 * 1000) return;
      try {
        await fetch('/lc/auth/refresh', { method: 'POST', credentials: 'include' });
      } catch {}
    }, 30 * 60 * 1000); // every 30 minutes
  }
});

const isOnChatPage = computed(() => route.path === '/chat');

function onDragStart(e: MouseEvent) {
  if ((e.target as HTMLElement).closest('button')) return; // Don't drag from buttons
  isDragging.value = true;
  const panel = (e.target as HTMLElement).closest('.lumichat-panel') as HTMLElement;
  if (!panel) return;
  const rect = panel.getBoundingClientRect();
  dragOffset.value = { x: e.clientX - rect.left, y: e.clientY - rect.top };
  document.addEventListener('mousemove', onDragMove);
  document.addEventListener('mouseup', onDragEnd);
  e.preventDefault();
}

function onDragMove(e: MouseEvent) {
  if (!isDragging.value) return;
  panelPos.value = {
    x: Math.max(0, Math.min(e.clientX - dragOffset.value.x, window.innerWidth - 420)),
    y: Math.max(0, Math.min(e.clientY - dragOffset.value.y, window.innerHeight - 100)),
  };
}

function onDragEnd() {
  isDragging.value = false;
  document.removeEventListener('mousemove', onDragMove);
  document.removeEventListener('mouseup', onDragEnd);
}

onMounted(() => {
  setTimezone(settingsStore.timezone);
  colorStore.updateProfitLossColor();
  window.addEventListener('toggle-lumichat', toggleLumiChat);
  window.addEventListener('lumichat-close-panel', closePanelWithAnimation);
  // Start auth check (runs during splash animation)
  checkAuthAndInit();
});

onBeforeUnmount(() => {
  window.removeEventListener('toggle-lumichat', toggleLumiChat);
  window.removeEventListener('lumichat-close-panel', closePanelWithAnimation);
  ACTIVITY_EVENTS.forEach(e => window.removeEventListener(e, trackActivity));
});

watch(
  () => settingsStore.timezone,
  (tz) => {
    console.log('timezone changed', tz);
    setTimezone(tz);
  },
);
</script>

<template>
  <!-- ═══ SPLASH SCREEN ═══ -->
  <div v-if="appState === 'splash'" class="lt-fullscreen-bg">
    <div class="lt-splash-scene">
      <svg class="lt-splash-ball" viewBox="0 0 40 40" width="64" height="64" fill="none" xmlns="http://www.w3.org/2000/svg">
        <circle cx="20" cy="20" r="20" fill="#10a37f"/>
        <polyline points="10 26 17 18 23 22 30 14" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
        <polyline points="25 14 30 14 30 19" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
      </svg>
      <div class="lt-splash-title">Lumi<span style="color:#10a37f">Trade</span></div>
    </div>
  </div>

  <!-- ═══ LOGIN SCREEN (LumiChat style) ═══ -->
  <div v-else-if="appState === 'login'" class="lt-fullscreen-bg">
    <div class="lt-login-card lt-card-enter">
      <div class="lt-login-logo">
        <svg viewBox="0 0 40 40" width="48" height="48" fill="none" xmlns="http://www.w3.org/2000/svg">
          <circle cx="20" cy="20" r="20" fill="#10a37f"/>
          <polyline points="10 26 17 18 23 22 30 14" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
          <polyline points="25 14 30 14 30 19" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
        </svg>
        <h1 class="lt-login-h1">Lumi<span style="color:#10a37f">Trade</span></h1>
      </div>

      <!-- Welcome step -->
      <div v-if="loginStep === 'welcome'" class="lt-form">
        <p class="lt-heading">Welcome</p>
        <p class="lt-sub">Log in or create an account</p>
        <button v-if="googleEnabled" class="lt-google-btn" @click="googleLogin">
          <svg width="18" height="18" viewBox="0 0 48 48"><path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.08 17.74 9.5 24 9.5z"/><path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/><path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"/><path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.18 1.48-4.97 2.31-8.16 2.31-6.26 0-11.57-3.59-13.46-8.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/></svg>
          <span>Continue with Google</span>
        </button>
        <div v-if="googleEnabled" class="lt-divider"><span>or</span></div>
        <input v-model="loginEmail" class="lt-input" type="email" placeholder="Email" autocomplete="email" @keydown.enter="continueWithEmail" />
        <button class="lt-btn-primary" :disabled="loginLoading" @click="continueWithEmail">
          {{ loginLoading ? 'Loading...' : 'Continue' }}
        </button>
        <p v-if="loginError" class="lt-error">{{ loginError }}</p>
      </div>

      <!-- Password step -->
      <div v-else-if="loginStep === 'password'" class="lt-form">
        <p class="lt-heading">Welcome back</p>
        <p class="lt-sub">{{ loginEmail }}</p>
        <input v-model="loginPassword" class="lt-input" type="password" placeholder="Password" autocomplete="off" @keydown.enter="doLogin" />
        <button class="lt-btn-primary" :disabled="loginLoading" @click="doLogin">
          {{ loginLoading ? 'Logging in...' : 'Continue' }}
        </button>
        <p class="lt-back-link"><a @click="loginStep = 'welcome'; loginError = ''">Use a different email</a></p>
        <p v-if="loginError" class="lt-error">{{ loginError }}</p>
      </div>

      <!-- Register step -->
      <div v-else-if="loginStep === 'register'" class="lt-form">
        <p class="lt-heading">Create account</p>
        <p class="lt-sub">{{ loginEmail }}</p>
        <input v-model="loginName" class="lt-input" type="text" placeholder="Display name" autocomplete="off" />
        <input v-model="loginPassword" class="lt-input" type="password" placeholder="Password (min 8 chars)" autocomplete="off" />
        <input v-model="loginPassword2" class="lt-input" type="password" placeholder="Confirm password" autocomplete="off" @keydown.enter="doRegister" />
        <button class="lt-btn-primary" :disabled="loginLoading" @click="doRegister">
          {{ loginLoading ? 'Creating...' : 'Create account' }}
        </button>
        <p class="lt-back-link"><a @click="loginStep = 'welcome'; loginError = ''">Use a different email</a></p>
        <p v-if="loginError" class="lt-error">{{ loginError }}</p>
      </div>
    </div>
  </div>

  <!-- ═══ MAIN APP (only when authenticated) ═══ -->
  <div v-else id="app" class="flex flex-col h-dvh" :style="colorStore.cssVars">
    <NavBar />
    <Toast />
    <BodyLayout class="grow overflow-auto" />
    <NavFooter />

    <!-- LumiTrader floating toggle button (hidden on full-page chat) -->
    <button
      v-if="!lumiChatOpen && !isOnChatPage"
      class="lumichat-fab"
      title="Open LumiTrader"
      @click="toggleLumiChat"
    >
      <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
        <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
      </svg>
    </button>

    <!-- LumiTrader floating panel -->
    <div
      v-if="lumiChatOpen"
      class="lumichat-panel"
      :class="{ 'lumichat-panel-closing': panelClosing }"
      :style="{
        left: panelPos.x >= 0 ? panelPos.x + 'px' : undefined,
        top: panelPos.y >= 0 ? panelPos.y + 'px' : undefined,
        right: panelPos.x < 0 ? '24px' : undefined,
        bottom: panelPos.y < 0 ? '24px' : undefined,
      }"
    >
      <div class="lumichat-panel-header" @mousedown="onDragStart">
        <div class="lumichat-panel-title">
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="opacity:0.7">
            <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
          </svg>
          <span>LumiTrader</span>
        </div>
        <div class="lumichat-panel-controls">
          <!-- Expand to full page -->
          <button class="lumichat-ctrl-btn" title="Open full page" @click="router.push('/chat')">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="15 3 21 3 21 9"/><polyline points="9 21 3 21 3 15"/><line x1="21" y1="3" x2="14" y2="10"/><line x1="3" y1="21" x2="10" y2="14"/></svg>
          </button>
          <!-- Minimize -->
          <button class="lumichat-ctrl-btn" title="Minimize" @click="lumiChatOpen = false">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><line x1="5" y1="12" x2="19" y2="12"/></svg>
          </button>
        </div>
      </div>
      <LumiTraderChat class="lumichat-panel-body" />
    </div>
  </div>
</template>

