  background: rgba(0,0,0,0.06);
  color: #0d0d0d;
}
:root.dark .lt-theme-toggle,
.ft-dark-theme .lt-theme-toggle {
  color: #999;
}
:root.dark .lt-theme-toggle:hover,
.ft-dark-theme .lt-theme-toggle:hover {
  background: rgba(255,255,255,0.08);
  color: #ececec;
}
.lt-theme-text {
  font-size: 13px;
  font-weight: 500;
}
</style>
