<script setup lang="ts">
import { ref, nextTick, onMounted, inject } from 'vue';
import type { Ref } from 'vue';

interface Message {
  role: 'user' | 'assistant';
  content: string;
}

interface Session {
  id: string;
  title: string;
  pair: string;
  messages: Message[];
  history: Message[];
}

const pbUser = inject<Ref<{ id: string; email: string; name: string; avatarUrl?: string } | null>>('pbUser');

// ── Sessions ──
const PAIRS = [
  { id: 'general', label: 'General', color: '#10a37f' },
  { id: 'BTC/USDT', label: 'BTC/USDT', color: '#f7931a' },
  { id: 'ETH/USDT', label: 'ETH/USDT', color: '#627eea' },
  { id: 'SOL/USDT', label: 'SOL/USDT', color: '#9945ff' },
];

const sessions = ref<Session[]>([
  { id: 'default', title: 'New chat', pair: 'general', messages: [], history: [] },
]);
const activeSessionId = ref('default');
const activePairId = ref('general'); // currently selected pair
const searchQuery = ref('');

const activeSession = (): Session => sessions.value.find(s => s.id === activeSessionId.value)!;

// Sessions filtered by current pair + search
function filteredSessions() {
  const q = searchQuery.value.trim().toLowerCase();
  return sessions.value.filter(s => {
    if (s.pair !== activePairId.value) return false;
    if (q && !s.title.toLowerCase().includes(q)) return false;
    return true;
  });
}

function selectPair(pairId: string) {
  activePairId.value = pairId;
  // Find first session for this pair, or create one
  const existing = sessions.value.find(s => s.pair === pairId);
  if (existing) {
    activeSessionId.value = existing.id;
  } else {
    newChat();
  }
  error.value = '';
  streaming.value = false;
  streamText.value = '';
  nextTick(() => scrollToBottom(true));
}

function newChat() {
  const pairId = activePairId.value;
  const id = 'sess-' + Date.now();
  const title = 'New chat';
  sessions.value.unshift({ id, title, pair: pairId, messages: [], history: [] });
  activeSessionId.value = id;
  error.value = '';
  streaming.value = false;
  streamText.value = '';
  nextTick(() => textareaRef.value?.focus());
}

function selectSession(id: string) {
  activeSessionId.value = id;
  error.value = '';
  streaming.value = false;
  streamText.value = '';
  nextTick(() => scrollToBottom(true));
}

// ── Chat state ──
const messages = (): Message[] => activeSession().messages;
const input = ref('');
const streaming = ref(false);
const streamText = ref('');
const messagesContainer = ref<HTMLElement | null>(null);
const textareaRef = ref<HTMLTextAreaElement | null>(null);
const error = ref('');

function scrollToBottom(force = false) {
  const el = messagesContainer.value;
  if (!el) return;
  const distFromBottom = el.scrollHeight - el.clientHeight - el.scrollTop;
  if (force || distFromBottom < 120) {
    el.scrollTop = el.scrollHeight;
  }
}

function autoResizeTextarea() {
  const ta = textareaRef.value;
  if (!ta) return;
  ta.style.height = 'auto';
  ta.style.height = Math.min(ta.scrollHeight, 120) + 'px';
}

async function send() {
  const text = input.value.trim();
  if (!text || streaming.value) return;

  error.value = '';
  input.value = '';
  if (textareaRef.value) textareaRef.value.style.height = 'auto';

  const sess = activeSession();
  const userMsg: Message = { role: 'user', content: text };
  sess.messages.push(userMsg);
  sess.history.push(userMsg);

  // Auto-title from first message
  if (sess.title === 'New chat' || sess.title === sess.pair) {
    sess.title = text.slice(0, 32) + (text.length > 32 ? '…' : '');
  }

  await nextTick();
  scrollToBottom(true);

  streaming.value = true;
  streamText.value = '';

  try {
    const pairCtx = sess.pair !== 'general' ? `[Trading pair: ${sess.pair}] ` : '';
    const resp = await fetch('/lumitrader/chat', {
      method: 'POST',
      credentials: 'include',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        messages: sess.history.map(m =>
          m.role === 'user' && m === sess.history[0] && pairCtx
            ? { ...m, content: pairCtx + m.content }
            : m
        ),
        model: 'gpt-4o',
        provider: 'openai',
        stream: true,
      }),
    });

    if (!resp.ok) {
      const errData = await resp.json().catch(() => ({}));
      throw new Error(errData.error || errData.message || `HTTP ${resp.status}`);
    }

    const reader = resp.body!.getReader();
    const decoder = new TextDecoder();
    let buffer = '';

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split('\n');
      buffer = lines.pop() ?? '';

      for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed || !trimmed.startsWith('data:')) continue;
        const payload = trimmed.slice(5).trim();
        if (payload === '[DONE]') continue;
        if (trimmed.startsWith('event:')) continue;
        try {
          const parsed = JSON.parse(payload);
          const delta =
            parsed?.choices?.[0]?.delta?.content ??
            parsed?.delta?.text ??
            parsed?.content ??
            '';
          if (delta) {
            streamText.value += delta;
            await nextTick();
            scrollToBottom();
          }
        } catch {
          if (payload && payload !== '[DONE]') {
            streamText.value += payload;
            await nextTick();
            scrollToBottom();
          }
        }
      }
    }

    // Flush remaining buffer
    if (buffer.trim()) {
      const trimmed = buffer.trim();
      if (trimmed.startsWith('data:')) {
        const payload = trimmed.slice(5).trim();
        if (payload && payload !== '[DONE]') {
          try {
            const parsed = JSON.parse(payload);
            const delta = parsed?.choices?.[0]?.delta?.content ?? parsed?.content ?? '';
            if (delta) streamText.value += delta;
          } catch {
            streamText.value += payload;
          }
        }
      }
    }

    const assistantMsg: Message = { role: 'assistant', content: streamText.value };
    sess.messages.push(assistantMsg);
    sess.history.push(assistantMsg);
    streamText.value = '';

    await nextTick();
    scrollToBottom(true);
  } catch (e: any) {
    error.value = e.message || 'Something went wrong';
    streamText.value = '';
  } finally {
    streaming.value = false;
  }
}

onMounted(() => {
  window.dispatchEvent(new CustomEvent('lumichat-close-panel'));
  textareaRef.value?.focus();
});
</script>

<template>
  <div class="lt-root">
    <!-- ── Sidebar ── -->
    <aside class="lt-sidebar">
      <!-- Top: New Chat button -->
      <div class="lt-sb-top">
        <button class="lt-new-btn" @click="newChat('general')" title="New chat">
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">
            <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
          </svg>
          New chat
        </button>
      </div>

      <!-- Search -->
      <div class="lt-sb-search">
        <div class="lt-sb-search-wrap">
          <svg class="lt-sb-search-ico" width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
          </svg>
          <input
            v-model="searchQuery"
            class="lt-sb-search-inp"
            type="text"
            placeholder="Search chats"
          />
        </div>
      </div>

      <!-- Session list -->
      <div class="lt-sb-list">
        <!-- Recent sessions -->
        <template v-if="filteredSessions().length > 0">
          <div class="lt-grp-label">Chats</div>
          <div
            v-for="sess in filteredSessions()"
            :key="sess.id"
            :class="['lt-sess-item', { active: sess.id === activeSessionId }]"
            @click="selectSession(sess.id)"
          >
            <span class="lt-sess-title">{{ sess.title }}</span>
          </div>
        </template>

        <!-- Pairs section — select pair, sessions filter by pair -->
        <div class="lt-grp-label" style="margin-top: 8px;">Pairs</div>
        <div
          v-for="pair in PAIRS"
          :key="pair.id"
          :class="['lt-pair-item', { 'lt-pair-active': pair.id === activePairId }]"
          @click="selectPair(pair.id)"
          :title="pair.id === 'general' ? 'General conversation' : pair.label"
        >
          <span class="lt-pair-dot" :style="{ background: pair.color }"></span>
          <span class="lt-pair-label">{{ pair.label }}</span>
        </div>
      </div>

      <!-- Footer: user info -->
      <div class="lt-sb-foot">
        <div class="lt-user-dot">
          {{ pbUser?.value ? (pbUser.value.name || pbUser.value.email || 'U')[0].toUpperCase() : 'LT' }}
        </div>
        <div class="lt-sb-foot-info">
          <div class="lt-sb-foot-name">
            {{ pbUser?.value ? (pbUser.value.name || pbUser.value.email?.split('@')[0] || 'Trader') : 'LumiTrader' }}
          </div>
          <div v-if="pbUser?.value?.email" class="lt-sb-foot-email">{{ pbUser.value.email }}</div>
        </div>
      </div>
    </aside>

    <!-- ── Main area ── -->
    <div class="lt-main">
      <!-- Messages area -->
      <div class="lt-messages" ref="messagesContainer">
        <div class="lt-messages-inner">
          <!-- Empty state -->
          <div v-if="messages().length === 0 && !streaming" class="lt-empty-state">
            <svg width="40" height="40" viewBox="0 0 40 40" fill="none" xmlns="http://www.w3.org/2000/svg">
              <circle cx="20" cy="20" r="20" fill="#10a37f" fill-opacity="0.12"/>
              <polyline points="10 26 17 18 23 22 30 14" stroke="#10a37f" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
              <polyline points="25 14 30 14 30 19" stroke="#10a37f" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
            </svg>
            <p class="lt-empty-title">LumiTrader</p>
            <p class="lt-empty-sub">Ask about your positions, analyze the market, or review your strategy.</p>
          </div>

          <!-- Message list -->
          <div
            v-for="(msg, i) in messages()"
            :key="i"
            :class="['lt-msg-row', msg.role === 'user' ? 'lt-msg-row-user' : 'lt-msg-row-asst']"
          >
            <div v-if="msg.role === 'user'" class="lt-user-bub">{{ msg.content }}</div>
            <div v-else class="lt-asst-content">{{ msg.content }}</div>
          </div>

          <!-- Streaming response -->
          <div v-if="streaming" class="lt-msg-row lt-msg-row-asst">
            <div class="lt-asst-content">
              <span>{{ streamText }}</span>
              <span v-if="!streamText" class="lt-typing-dots">
                <span class="lt-tdot"></span>
                <span class="lt-tdot"></span>
                <span class="lt-tdot"></span>
              </span>
            </div>
          </div>

          <!-- Error -->
          <div v-if="error" class="lt-error-banner">{{ error }}</div>
        </div>
      </div>

      <!-- Input area -->
      <div class="lt-input-area">
        <div class="lt-inp-box">
          <textarea
            ref="textareaRef"
            v-model="input"
            class="lt-inp-ta"
            placeholder="Message LumiTrader"
            rows="1"
            @keydown.enter.exact.prevent="send"
            @input="autoResizeTextarea"
          ></textarea>
          <div class="lt-inp-bar">
            <div class="lt-inp-left"></div>
            <button
              class="lt-send-btn"
              :disabled="!input.trim() || streaming"
              @click="send"
              title="Send"
            >
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">
                <line x1="12" y1="19" x2="12" y2="5"/>
                <polyline points="5 12 12 5 19 12"/>
              </svg>
            </button>
          </div>
        </div>
        <p class="lt-disclaimer">LumiTrader can make mistakes. Always verify before trading.</p>
      </div>
    </div>
  </div>
</template>

