const STORE_UI_COLORS = 'ftUIColorSettings';

export enum ColorPreferences {
  GREEN_UP = 'greenUp',
  RED_UP = 'redUp',
  CUSTOM = 'custom',
}

export const useColorStore = defineStore('colorStore', {
  // other options...
  state: () => {
    return {
      colorPreference: ColorPreferences.GREEN_UP,
      colorUp: '#22c55e',      // LumiChat green
      colorDown: '#ef4444',     // LumiChat red
      colorProfit: '#22c55e',
      colorLoss: '#ef4444',
      // Custom candle colors (user-configurable)
      customColorUp: '#22c55e',
      customColorDown: '#ef4444',
    };
  },
  getters: {
    cssVars(state) {
      return {
        '--color-profit': state.colorProfit,
        '--color-loss': state.colorLoss,
      };
    },
  },
  actions: {
    updateProfitLossColor() {
      if (this.colorPreference === ColorPreferences.CUSTOM) {
        this.colorUp = this.customColorUp;
        this.colorDown = this.customColorDown;
        return;
      }
      const [colorUp, colorDown] =
        this.colorPreference === ColorPreferences.GREEN_UP
          ? ['#22c55e', '#ef4444']
          : ['#ef4444', '#22c55e'];
      this.colorUp = colorUp;
      this.colorDown = colorDown;
    },
    setCustomColors(up: string, down: string) {
      this.customColorUp = up;
      this.customColorDown = down;
      this.colorPreference = ColorPreferences.CUSTOM;
      this.updateProfitLossColor();
    },
  },
  persist: {
    key: STORE_UI_COLORS,
    pick: ['colorPreference', 'customColorUp', 'customColorDown'],
  },
});

if (import.meta.hot) {
  import.meta.hot.accept(acceptHMRUpdate(useColorStore, import.meta.hot));
}
