<script setup lang="ts">
import Favico from 'favico.js';

import { useRoute } from 'vue-router';
import { inject } from 'vue';
import type { Ref } from 'vue';
import Menu from 'primevue/menu';
import type { MenuItem } from 'primevue/menuitem';
import { breakpointsTailwind } from '@vueuse/core';

const pbUser = inject<Ref<{ id: string; email: string; name: string; avatarUrl?: string } | null>>('pbUser');
const doLogout = inject<() => Promise<void>>('doLogout');

const botStore = useBotStore();
const settingsStore = useSettingsStore();
const layoutStore = useLayoutStore();
const route = useRoute();
const router = useRouter();
const favicon = ref<Favico | undefined>(undefined);
const pingInterval = ref<number>();

const breakpoints = useBreakpoints(breakpointsTailwind);
const isMobile = breakpoints.smallerOrEqual('md');

async function clickLogout() {
  if (doLogout) await doLogout();
}

const setOpenTradesAsPill = (tradeCount: number) => {
  if (!favicon.value) {
    favicon.value = new Favico({ animation: 'none' });
  }
  if (tradeCount !== 0 && settingsStore.openTradesInTitle === 'showPill') {
    favicon.value.badge(tradeCount);
  } else {
    favicon.value.reset();
  }
};

const resetDynamicLayout = (): void => {
  switch (route?.fullPath) {
    case '/trade':
      layoutStore.resetTradingLayout();
      break;
    case '/dashboard':
      layoutStore.resetDashboardLayout();
      break;
    default:
  }
};

const setTitle = () => {
  let title = 'LumiTrade';
  if (settingsStore.openTradesInTitle === OpenTradeVizOptions.asTitle) {
    title = `(${botStore.activeBotorUndefined?.openTradeCount}) ${title}`;
  }
  if (botStore.activeBotorUndefined?.botName) {
    title = `${title} - ${botStore.activeBotorUndefined?.botName}`;
  }
  document.title = title;
};

onBeforeUnmount(() => {
  if (pingInterval.value) {
    clearInterval(pingInterval.value);
  }
});

onMounted(async () => {
  await settingsStore.loadUIVersion();
  pingInterval.value = window.setInterval(botStore.pingAll, 60000);
});

settingsStore.$subscribe((_, state) => {
  const needsUpdate = settingsStore.openTradesInTitle !== state.openTradesInTitle;
  if (needsUpdate) {
    setTitle();
    setOpenTradesAsPill(botStore.activeBotorUndefined?.openTradeCount || 0);
  }
});

watch(
  () => botStore.activeBotorUndefined?.botName,
  () => setTitle(),
);
watch(
  () => botStore.activeBotorUndefined?.openTradeCount,
  () => {
    if (settingsStore.openTradesInTitle === OpenTradeVizOptions.showPill) {
      setOpenTradesAsPill(botStore.activeBotorUndefined?.openTradeCount ?? 0);
    } else if (settingsStore.openTradesInTitle === OpenTradeVizOptions.asTitle) {
      setTitle();
    }
  },
);

// ----- Nav items -----
// icon field is a string key used for v-if in template to select the right component
const navItems = ref([
  {
    label: 'Trade',
    to: '/trade',
    visible: computed(() => !botStore.canRunBacktest),
    icon: 'dollar-sign',
  },
  {
    label: 'Dashboard',
    to: '/dashboard',
    visible: computed(() => !botStore.canRunBacktest),
    icon: 'layout-dashboard',
  },
  {
    label: 'Chart',
    to: '/graph',
    icon: 'trending-up',
  },
  {
    label: 'Backtest',
    to: '/backtest',
    icon: 'flask-conical',
  },
  {
    label: 'LumiTrader',
    to: '/chat',
    icon: 'message-square',
  },
  {
    label: 'Logs',
    to: '/logs',
    icon: 'scroll-text',
  },
  {
    label: 'Settings',
    to: '/settings',
    mobileOnly: true,
    icon: 'settings',
  },
  {
    label: 'Backtest',
    to: '/backtest',
    visible: computed(() => botStore.canRunBacktest),
    icon: 'dollar-sign',
  },
  {
    label: 'Download Data',
    to: '/download_data',
    visible: computed(
      () => botStore.isWebserverMode && botStore.activeBot.botFeatures.downloadDataView,
    ),
    icon: 'download',
  },
  {
    label: 'Pairlist Config',
    to: '/pairlist_config',
    icon: 'list',
    visible: computed(
      () =>
        (botStore.activeBot?.isWebserverMode ?? false) &&
        botStore.activeBot.botFeatures.pairlistConfig,
    ),
  },
]);

const menuItems = computed<MenuItem[]>(() => [
  {
    label: `V: ${settingsStore.uiVersion}`,
    disabled: true,
  },
  {
    label: 'Settings',
    icon: 'settings',
    command: () => router.push('/settings'),
  },
  {
    label: 'Lock Layout',
    checkbox: true,
    checked: layoutStore.layoutLocked,
    command: () => {
      layoutStore.layoutLocked = !layoutStore.layoutLocked;
    },
  },
  {
    label: 'Reset Layout',
    icon: 'rotate-ccw',
    command: resetDynamicLayout,
  },
  {
    label: 'Logout',
    icon: 'log-out',
    command: clickLogout,
  },
]);

const menu = ref<InstanceType<typeof Menu> | null>();
function toggleMenu(event: Event) {
  menu.value?.toggle(event);
}
const drawerVisible = ref(false);

function toggleLumiChat() {
  window.dispatchEvent(new CustomEvent('toggle-lumichat'));
}

// Bot online status for display
const botOnline = computed(() => botStore.activeBotorUndefined?.isBotOnline ?? false);
</script>

<template>
  <header>
    <div class="flex border-b lt-header">
      <!-- Logo -->
      <RouterLink class="ms-2 flex flex-row items-center pe-2 gap-2 flex-shrink-0" exact to="/">
        <svg class="h-[26px] w-[26px] align-middle flex-shrink-0" viewBox="0 0 40 40" xmlns="http://www.w3.org/2000/svg">
          <circle cx="20" cy="20" r="20" fill="#10a37f"/>
          <polyline points="10 26 17 18 23 22 30 14" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
          <polyline points="25 14 30 14 30 19" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" fill="none"/>
        </svg>
        <span class="text-xl md:hidden lg:inline text-nowrap font-bold text-[#0d0d0d] dark:text-white">
          Lumi<span class="text-[#10a37f]">Trade</span>
        </span>
      </RouterLink>

      <div class="flex justify-between w-full items-center ms-3">

        <!-- Desktop nav links (icon + label) -->
        <nav class="items-center hidden md:flex gap-1 ms-3" aria-label="Main navigation">
          <template
            v-for="(item, index) in navItems.filter(
              (i) => (i.visible === undefined || (typeof i.visible === 'object' ? i.visible.value : i.visible)) && !i.mobileOnly,
            )"
            :key="index"
          >
            <a
              v-if="(item as any).isLumiChat"
              class="lt-nav-link flex items-center gap-2 cursor-pointer"
              @click="toggleLumiChat()"
            >
              <i-lucide-message-square class="w-4 h-4 flex-shrink-0" />
              <span>{{ item.label }}</span>
            </a>
            <RouterLink
              v-else
              :to="item.to"
              class="lt-nav-link flex items-center gap-2"
              active-class="lt-nav-active"
            >
              <!-- Icon per name -->
              <i-lucide-dollar-sign      v-if="item.icon === 'dollar-sign'"      class="w-4 h-4 flex-shrink-0" />
              <i-lucide-layout-dashboard v-else-if="item.icon === 'layout-dashboard'" class="w-4 h-4 flex-shrink-0" />
              <i-lucide-trending-up      v-else-if="item.icon === 'trending-up'"  class="w-4 h-4 flex-shrink-0" />
              <i-lucide-flask-conical    v-else-if="item.icon === 'flask-conical'" class="w-4 h-4 flex-shrink-0" />
              <i-lucide-message-square   v-else-if="item.icon === 'message-square'" class="w-4 h-4 flex-shrink-0" />
              <i-lucide-scroll-text      v-else-if="item.icon === 'scroll-text'"  class="w-4 h-4 flex-shrink-0" />
              <i-lucide-download         v-else-if="item.icon === 'download'"     class="w-4 h-4 flex-shrink-0" />
              <i-lucide-list             v-else-if="item.icon === 'list'"         class="w-4 h-4 flex-shrink-0" />
              <i-lucide-settings         v-else-if="item.icon === 'settings'"     class="w-4 h-4 flex-shrink-0" />
              <span>{{ item.label }}</span>
            </RouterLink>
          </template>

          <ThemeSelect class="ms-1" />
        </nav>

        <!-- Right side -->
        <div class="flex items-center ms-auto gap-2">

          <!-- Confirm dialog warning -->
          <div
            v-if="!isMobile && !settingsStore.confirmDialog"
            class="flex items-center gap-1 text-yellow-400"
            title="Confirm dialog deactivated — forced exits execute immediately."
          >
            <i-lucide-zap class="w-4 h-4" />
            <i-lucide-alert-triangle class="w-4 h-4" />
          </div>

          <!-- Multi-bot selector -->
          <Select
            v-if="!isMobile && botStore.botCount > 1"
            :model-value="botStore.selectedBotObj"
            size="small"
            class="m-1"
            no-caret
            severity="info"
            toggle-class="flex align-items-center"
            menu-class="my-0 py-0"
            :options="botStore.availableBotsSorted"
            @update:model-value="botStore.selectBot($event.botId)"
          >
            <template #value="{ value }">
              <BotEntry :bot="value" :no-buttons="true" />
            </template>
            <template #option="{ option }">
              <BotEntry :bot="option" :no-buttons="true" />
            </template>
          </Select>

          <!-- Reload control -->
          <ReloadControl v-if="!isMobile" class="me-1" title="Confirm Dialog deactivated." />

          <!-- Desktop: bot status + avatar menu -->
          <template v-if="!isMobile">
            <div v-if="botStore.hasBots" class="flex items-center gap-2">
              <!-- Online/Offline dot -->
              <span
                v-if="botStore.botCount === 1"
                class="lt-status-dot"
                :class="botOnline ? 'lt-status-online' : 'lt-status-offline'"
                :title="botOnline ? 'Online' : 'Offline'"
              />

              <!-- Avatar + chevron dropdown -->
              <Button severity="contrast" variant="text" size="small" class="lt-avatar-btn" @click="toggleMenu">
                <div class="flex items-center gap-1">
                  <Avatar shape="circle" severity="contrast" class="lt-avatar">
                    {{ pbUser?.value ? (pbUser.value.name || pbUser.value.email || 'U')[0].toUpperCase() : 'LT' }}
                  </Avatar>
                  <span v-if="pbUser?.value" class="text-sm font-medium hidden lg:inline">
                    {{ pbUser.value.name || pbUser.value.email?.split('@')[0] || 'User' }}
                  </span>
                  <i-lucide-chevron-down class="w-3.5 h-3.5 opacity-60" />
                </div>
              </Button>

              <Menu ref="menu" :model="menuItems" popup class="w-52">
                <template #item="{ item }">
                  <div
                    class="lt-menu-item flex items-center gap-2 px-3 py-2 cursor-pointer rounded-lg"
                    :class="{ 'opacity-50 cursor-default': item.disabled }"
                  >
                    <i-lucide-settings   v-if="item.icon === 'settings'"   class="w-4 h-4 flex-shrink-0" />
                    <i-lucide-log-out    v-if="item.icon === 'log-out'"    class="w-4 h-4 flex-shrink-0" />
                    <i-lucide-rotate-ccw v-if="item.icon === 'rotate-ccw'" class="w-4 h-4 flex-shrink-0" />
                    <BaseCheckbox v-if="item.checkbox" v-model="item.checked" class="flex-shrink-0" />
                    <span class="text-sm">{{ item.label }}</span>
                  </div>
                </template>
              </Menu>
            </div>

            <!-- Not logged in -->
            <div v-else>
              <LoginModal v-if="route?.path !== '/login'" />
            </div>
          </template>

          <!-- Mobile hamburger -->
          <Button
            v-if="isMobile"
            class="lt-mobile-menu-btn"
            variant="text"
            @click="drawerVisible = !drawerVisible"
          >
            <template #icon>
              <i-lucide-menu class="w-5 h-5" />
            </template>
          </Button>
        </div>
      </div>
    </div>

    <!-- Mobile drawer (frosted glass, LumiChat-style) -->
    <Drawer
      v-model:visible="drawerVisible"
      position="right"
      class="lt-mobile-drawer"
    >
      <template #container>
        <div class="lt-drawer-inner flex flex-col h-full">

          <!-- Drawer header -->
          <div class="flex items-center justify-between px-5 py-4 border-b lt-drawer-header">
            <span class="text-lg font-bold text-[#0d0d0d] dark:text-white">
              Lumi<span class="text-[#10a37f]">Trade</span>
            </span>
            <Button variant="text" size="small" class="lt-close-btn" @click="drawerVisible = false">
              <template #icon>
                <i-lucide-x class="w-5 h-5" />
              </template>
            </Button>
          </div>

          <!-- Nav links -->
          <nav class="flex flex-col gap-1 px-3 pt-4 flex-1 overflow-y-auto">
            <template
              v-for="(item, index) in navItems.filter(
                (i) => i.visible === undefined || (typeof i.visible === 'object' ? i.visible.value : i.visible),
              )"
              :key="index"
            >
              <a
                v-if="(item as any).isLumiChat"
                class="lt-drawer-link flex items-center gap-3 cursor-pointer"
                @click="drawerVisible = false; toggleLumiChat()"
              >
                <i-lucide-message-square class="w-5 h-5 flex-shrink-0" />
                <span>{{ item.label }}</span>
              </a>
              <RouterLink
                v-else
                :to="item.to"
                class="lt-drawer-link flex items-center gap-3"
                active-class="lt-drawer-active"
                @click="drawerVisible = false"
              >
                <i-lucide-dollar-sign      v-if="item.icon === 'dollar-sign'"      class="w-5 h-5 flex-shrink-0" />
                <i-lucide-layout-dashboard v-else-if="item.icon === 'layout-dashboard'" class="w-5 h-5 flex-shrink-0" />
                <i-lucide-trending-up      v-else-if="item.icon === 'trending-up'"  class="w-5 h-5 flex-shrink-0" />
                <i-lucide-flask-conical    v-else-if="item.icon === 'flask-conical'" class="w-5 h-5 flex-shrink-0" />
                <i-lucide-message-square   v-else-if="item.icon === 'message-square'" class="w-5 h-5 flex-shrink-0" />
                <i-lucide-scroll-text      v-else-if="item.icon === 'scroll-text'"  class="w-5 h-5 flex-shrink-0" />
                <i-lucide-download         v-else-if="item.icon === 'download'"     class="w-5 h-5 flex-shrink-0" />
                <i-lucide-list             v-else-if="item.icon === 'list'"         class="w-5 h-5 flex-shrink-0" />
                <i-lucide-settings         v-else-if="item.icon === 'settings'"     class="w-5 h-5 flex-shrink-0" />
                <span>{{ item.label }}</span>
              </RouterLink>
            </template>
          </nav>

          <!-- Drawer footer -->
          <div class="px-5 py-4 border-t lt-drawer-footer flex flex-col gap-3">
            <!-- Multi-bot selector in drawer -->
            <Select
              v-if="botStore.botCount > 1"
              :model-value="botStore.selectedBotObj"
              size="small"
              no-caret
              severity="info"
              toggle-class="flex align-items-center"
              menu-class="my-0 py-0"
              :options="botStore.availableBotsSorted"
              @update:model-value="botStore.selectBot($event.botId)"
            >
              <template #value="{ value }">
                <BotEntry :bot="value" :no-buttons="true" />
              </template>
              <template #option="{ option }">
                <BotEntry :bot="option" :no-buttons="true" />
              </template>
            </Select>

            <ReloadControl class="w-full justify-center" title="Confirm Dialog deactivated." />

            <!-- Theme + version row -->
            <div class="flex items-center justify-between">
              <ThemeSelect show-text />
              <span class="text-xs text-surface-400">v{{ settingsStore.uiVersion }}</span>
            </div>

            <!-- PB user info -->
            <div v-if="pbUser?.value" class="flex items-center gap-3 px-4 py-3">
              <div class="w-8 h-8 rounded-full bg-[#10a37f] flex items-center justify-center text-white text-sm font-bold flex-shrink-0">
                {{ (pbUser.value.name || pbUser.value.email || 'U')[0].toUpperCase() }}
              </div>
              <div class="flex-1 min-w-0">
                <div class="text-sm font-medium truncate">{{ pbUser.value.name || pbUser.value.email?.split('@')[0] }}</div>
                <div class="text-xs text-surface-400 truncate">{{ pbUser.value.email }}</div>
              </div>
            </div>

            <!-- Logout -->
            <button
              class="lt-drawer-link flex items-center gap-3 w-full text-left text-red-500"
              @click="drawerVisible = false; clickLogout()"
            >
              <i-lucide-log-out class="w-5 h-5 flex-shrink-0" />
              <span>Logout</span>
            </button>
          </div>
        </div>
      </template>
    </Drawer>
  </header>
</template>

