import { createPinia } from 'pinia';
import piniaPluginPersistedstate from 'pinia-plugin-persistedstate';

import App from './App.vue';
import { VueDraggableGrid } from './plugins/vue-grid-layout';
import router from './router';

import { PrimeVue, FtTheme, ToastService } from './plugins/primevue';

// Auth is fully managed by App.vue (splash → login → app).
// No pre-mount auto-login needed — App.vue handles the entire auth gate.
async function bootstrap() {
  const myApp = createApp(App);

  const pinia = createPinia();
  pinia.use(piniaPluginPersistedstate);
  myApp.use(pinia);

  myApp.use(PrimeVue, {
    theme: {
      preset: FtTheme,
      options: {
        darkModeSelector: '.ft-dark-theme',
        cssLayer: {
          name: 'primevue',
          order: 'theme, base, primevue',
        },
      },
    },
  });
  myApp.use(ToastService);

  myApp.use(router);
  myApp.use(VueDraggableGrid);

  myApp.mount('#app');
}

bootstrap();
